const AppRouter=(()=>{const routes={};let currentRoute=null;let outlet=null;function register(name,{path:path,enter:enter,leave:leave}){routes[name]={path:path,enter:enter,leave:leave}}function resolve(hash){const clean=hash.replace(/^#/,"")||"/";for(const[name,route]of Object.entries(routes)){if(route.path===clean)return{name:name,...route}}return null}function navigate(hash,pushState=true){if(pushState){window.location.hash=hash}const matched=resolve(hash);if(!matched)return;if(currentRoute&&currentRoute.leave)currentRoute.leave();currentRoute=matched;if(currentRoute.enter)currentRoute.enter(outlet)}function start(selector){outlet=document.querySelector(selector);if(!outlet){outlet=document.getElementById("app-content")||document.body}window.addEventListener("hashchange",()=>{navigate(window.location.hash,false)});navigate(window.location.hash||"#/",false)}return{register:register,navigate:navigate,start:start,resolve:resolve}})();window.AppRouter=AppRouter;